// ─── FUNCTIES ─────────────────────────────────────────────────────────────────

function psp_vind_email($naam, &$naam_email_map) {
    // 1. Exacte match
    $lc = strtolower($naam);
    if (isset($naam_email_map[$lc])) return $naam_email_map[$lc];
    // 2. similar_text match (drempel 72%)
    $beste_score = 0;
    $beste_email = null;
    foreach ($naam_email_map as $wp_naam => $email) {
        similar_text($lc, $wp_naam, $perc);
        if ($perc > $beste_score) {
            $beste_score = $perc;
            $beste_email = $email;
        }
    }
    if ($beste_score >= 72 && $beste_email) return $beste_email;
    return null;
}

function psp_maak_account($naam, &$naam_email_map) {
    // Geen emails sturen
    add_filter('wp_new_user_notification_email',       '__return_false');
    add_filter('wp_new_user_notification_email_admin', '__return_false');
    remove_all_actions('user_register');

    $slug      = sanitize_user(str_replace([' ', '  '], ['.', '.'], strtolower($naam)), true);
    $slug      = preg_replace('/\.{2,}/', '.', $slug);
    $gen_email = $slug . '@psplanning.nl';

    // Check of login/email al bestaat
    if (get_user_by('login', $slug)) {
        $slug .= rand(10, 99);
        $gen_email = $slug . '@psplanning.nl';
    }
    if (email_exists($gen_email)) {
        return email_exists($gen_email) ? get_userdata(email_exists($gen_email))->user_email : $gen_email;
    }

    $user_id = wp_insert_user([
        'user_login'   => $slug,
        'user_email'   => $gen_email,
        'display_name' => $naam,
        'first_name'   => explode(' ', $naam)[0],
        'user_pass'    => wp_generate_password(20, true),
        'role'         => 'psp_student',
    ]);

    if (is_wp_error($user_id)) {
        return $gen_email; // email terugsturen ook al mislukt insert
    }

    $naam_email_map[strtolower($naam)] = $gen_email;
    return $gen_email;
}


