// ─── UITVOEREN ────────────────────────────────────────────────────────────────
global $wpdb;

// E-mails blokkeren
add_filter('wp_new_user_notification_email',       '__return_false');
add_filter('wp_new_user_notification_email_admin', '__return_false');
remove_all_actions('user_register');

$log = [];
$fouten = 0;

// 1. Alles leeg maken
$wpdb->query("TRUNCATE TABLE " . TB_BESCH);
$wpdb->query("TRUNCATE TABLE " . TB_DIENST);
$wpdb->query("TRUNCATE TABLE " . TB_KOPPEL);
$log[] = "✅ Tabellen geleegd";

// 2. WP gebruikers ophalen
$wp_users = get_users(['role__in' => ['psp_student', 'psp_aanvraag', 'editor', 'administrator']]);
$naam_email_map = [];
foreach ($wp_users as $u) {
    $naam_email_map[strtolower($u->display_name)] = $u->user_email;
}
$log[] = "👥 WP gebruikers geladen: " . count($naam_email_map);

// 3. Voor elke unieke naam email bepalen / account aanmaken
$naam_to_email = [];
$nieuw = 0;
$gematcht = 0;
foreach ($unieke_namen as $naam) {
    $email = psp_vind_email($naam, $naam_email_map);
    if ($email) {
        $gematcht++;
    } else {
        $email = psp_maak_account($naam, $naam_email_map);
        $nieuw++;
    }
    $naam_to_email[$naam] = $email;
}
$log[] = "🔍 Namen gematcht: {$gematcht}, Nieuwe accounts: {$nieuw}";

// 4. Beschikbaarheid invoegen
$besch_id_map = [];
$besch_ok = 0;
foreach ($beschikbaarheid_data as $idx => $b) {
    [$naam, $week_start, $klant, $status_oo, $dagen] = $b;
    $email = $naam_to_email[$naam] ?? ($naam . '@psplanning.nl');
    $ok = $wpdb->insert(TB_BESCH, [
        'naam'       => $naam,
        'email'      => $email,
        'week_start' => $week_start,
        'dagen'      => json_encode($dagen, JSON_UNESCAPED_UNICODE),
        'voorkeur'   => '',
        'status'     => 'actief',
    ]);
    if ($ok) {
        $besch_id_map[$idx] = $wpdb->insert_id;
        $besch_ok++;
    } else {
        $fouten++;
    }
}
$log[] = "📋 Beschikbaarheid ingevoegd: {$besch_ok}";

// 5. Diensten invoegen
$dienst_id_map = [];
$dienst_ok = 0;
foreach ($diensten_data as $idx => $d) {
    [$klant, $week_start, $datum, $van, $tot, $naam, $omschrijving] = $d;
    $ok = $wpdb->insert(TB_DIENST, [
        'klant'       => $klant,
        'week_start'  => $week_start,
        'datum'       => $datum,
        'van_tijd'    => $van,
        'tot_tijd'    => $tot,
        'type_werk'   => $naam,
        'omschrijving'=> $omschrijving,
        'status'      => 'actief',
    ]);
    if ($ok) {
        $dienst_id_map[$idx] = $wpdb->insert_id;
        $dienst_ok++;
    } else {
        $fouten++;
    }
}
$log[] = "🗓️ Diensten ingevoegd: {$dienst_ok}";

// 6. Koppelingen invoegen
$koppel_ok = 0;
foreach ($koppelingen_data as $k) {
    $b_id = $besch_id_map[$k[0]] ?? null;
    $d_id = $dienst_id_map[$k[1]] ?? null;
    if ($b_id && $d_id) {
        $wpdb->insert(TB_KOPPEL, [
            'beschikbaarheid_id' => $b_id,
            'dienst_id'          => $d_id,
        ]);
        $koppel_ok++;
    }
}
$log[] = "🔗 Koppelingen ingevoegd: {$koppel_ok}";

// ─── RESULTAAT ────────────────────────────────────────────────────────────────
echo '<!DOCTYPE html><html><head><meta charset="utf-8"><title>PSP Reimport Klaar</title>';
echo '<style>body{font-family:sans-serif;max-width:900px;margin:40px auto;padding:20px}';
echo '.ok{background:#d4edda;border:1px solid #28a745;padding:16px;border-radius:8px;margin:8px 0}';
echo '.err{background:#f8d7da;border:1px solid #dc3545;padding:16px;border-radius:8px;margin:8px 0}';
