echo '<h1>PSP Reimport Resultaat</h1>';
foreach ($log as $r) echo "<div class=ok>{$r}</div>";
if ($fouten > 0) echo "<div class=err>⚠️ Fouten: {$fouten}</div>";
echo "<div class=ok>✅ Import klaar! <a href='" . home_url('/planning-dashboard/') . "'>Naar dashboard →</a></div>";
